import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Admin() {
  const [requests, setRequests] = useState([]);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const adminPassword = "admin123";

  // डेटाबेस से डेटा लाने का फंक्शन
  const fetchData = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setRequests(res.data);
    } catch (err) {
      console.error("Error fetching data:", err);
    }
  };

  useEffect(() => {
    if (isLoggedIn) {
      fetchData();
    }
  }, [isLoggedIn]);

  const handleLogin = (e) => {
    e.preventDefault();
    if (password === adminPassword) {
      setIsLoggedIn(true);
    } else {
      alert("Wrong Password!");
    }
  };

  // स्टेटस और प्रोग्रेस अपडेट करने का फंक्शन
  const handleUpdate = async (id, currentStatus, currentProgress) => {
    try {
      const res = await axios.put(`http://localhost:5000/api/update-status/${id}`, {
        status: currentStatus,
        progress: currentProgress
      });
      if (res.status === 200) {
        alert("Project Updated Successfully!");
        fetchData(); // लिस्ट को रिफ्रेश करें
      }
    } catch (err) {
      console.error("Update error:", err);
      alert("Failed to update status.");
    }
  };

  if (!isLoggedIn) {
    return (
      <div className="container py-5 text-center mt-5">
        <div className="card shadow p-4 mx-auto border-0" style={{ maxWidth: '400px' }}>
          <h3 className="fw-bold mb-4">Admin Dashboard</h3>
          <form onSubmit={handleLogin}>
            <input 
              type="password" 
              className="form-control mb-3 text-center" 
              placeholder="Enter Password" 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              required
            />
            <button className="btn btn-dark w-100 fw-bold shadow-sm">Login</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="container py-5">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2 className="fw-bold text-primary">Client Project Management</h2>
        <button className="btn btn-danger btn-sm px-4" onClick={() => setIsLoggedIn(false)}>Logout</button>
      </div>

      <div className="table-responsive shadow-lg rounded-4 p-3 bg-white border">
        <table className="table table-hover align-middle">
          <thead className="table-dark">
            <tr>
              <th>Client Name</th>
              <th>Service</th>
              <th>Progress (%)</th>
              <th>Status</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {requests.length > 0 ? requests.map((req) => (
              <tr key={req._id}>
                <td className="fw-bold">{req.fullName}</td>
                <td><span className="badge bg-info text-dark">{req.serviceType}</span></td>
                <td>
                  <input 
                    type="number" 
                    className="form-control form-control-sm" 
                    style={{ width: '80px' }}
                    defaultValue={req.progress}
                    id={`progress-${req._id}`}
                  />
                </td>
                <td>
                  <select 
                    className="form-select form-select-sm" 
                    defaultValue={req.status}
                    id={`status-${req._id}`}
                  >
                    <option value="Pending">Pending</option>
                    <option value="In Progress">In Progress</option>
                    <option value="Completed">Completed</option>
                  </select>
                </td>
                <td>
                  <button 
                    className="btn btn-success btn-sm px-3"
                    onClick={() => {
                      const newStatus = document.getElementById(`status-${req._id}`).value;
                      const newProgress = document.getElementById(`progress-${req._id}`).value;
                      handleUpdate(req._id, newStatus, newProgress);
                    }}
                  >
                    Update
                  </button>
                </td>
              </tr>
            )) : (
              <tr><td colSpan="5" className="text-center py-4 text-muted">No Project Requests Yet.</td></tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default Admin;
